using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration – set OPENAI_API_KEY (or OPENAI_BASE_URL for compatible APIs)
// ---------------------------------------------------------------------------
var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY")  ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL")    ?? "gpt-4o-mini";
var baseUrl = Environment.GetEnvironmentVariable("OPENAI_BASE_URL");

var clientOptions = new OpenAIClientOptions();
if (baseUrl is not null)
    clientOptions.Endpoint = new Uri(baseUrl);

IChatClient innerClient = new OpenAIClient(apiKey, clientOptions).GetChatClient(model).AsIChatClient();

// Register the two tools with the chat client
var notepad = new NotepadTool();

var chatClient = innerClient
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(WebSearchTool.Search),
        AIFunctionFactory.Create(notepad.AddNote),
        AIFunctionFactory.Create(notepad.GetNotes),
    ],
    Temperature = 0.2f,
};

// ---------------------------------------------------------------------------
// Agent system prompt
// ---------------------------------------------------------------------------
var systemPrompt = """
    You are a research assistant agent.  Your job is to research a topic the
    user gives you by searching the web, taking notes on what you find, and
    finally producing a concise summary.

    Workflow:
    1. Break the topic into 2-4 search queries that cover the subject well.
    2. For each query, call the `Search` tool to get results.
    3. Read through the results and call `AddNote` to save every important
       fact, statistic, or quote together with its source URL.
    4. After you have gathered enough information, call `GetNotes` to review
       everything you saved.
    5. Write a well-structured summary using the notes. Cite sources inline.

    Always search before answering.  Never fabricate information.
    """;

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("  Research Agent  (type 'exit' to quit)");
Console.WriteLine("═══════════════════════════════════════════");

var history = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
};

while (true)
{
    Console.Write("\nTopic> ");
    var input = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(input) || input.Equals("exit", StringComparison.OrdinalIgnoreCase))
        break;

    // Clear notes for each new research session
    notepad.Clear();
    history.Add(new(ChatRole.User, input));

    Console.WriteLine("\n🔍  Researching…\n");

    var response = await chatClient.GetResponseAsync(history, chatOptions);
    history.AddRange(response.Messages);

    Console.WriteLine(response.Text);
}

Console.WriteLine("\nGoodbye!");

// ═══════════════════════════════════════════════════════════════════════════
// Tools
// ═══════════════════════════════════════════════════════════════════════════

/// <summary>Simulated web search tool that returns results for a query.</summary>
public static class WebSearchTool
{
    private static readonly HttpClient Http = new();

    [Description("Search the web for the given query and return a JSON array of results with title, url, and snippet.")]
    public static async Task<string> Search(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        // Try Brave Search API if a key is available, otherwise fall back to
        // a deterministic stub so the app still runs without credentials.
        var braveKey = Environment.GetEnvironmentVariable("BRAVE_API_KEY");
        if (braveKey is not null)
        {
            try
            {
                var url = $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count=5";
                using var request = new HttpRequestMessage(HttpMethod.Get, url);
                request.Headers.Add("X-Subscription-Token", braveKey);
                request.Headers.Accept.Add(new("application/json"));

                var resp = await Http.SendAsync(request);
                resp.EnsureSuccessStatusCode();
                var json = await resp.Content.ReadAsStringAsync();

                using var doc = JsonDocument.Parse(json);
                var results = doc.RootElement.GetProperty("web").GetProperty("results");

                var items = new List<object>();
                foreach (var r in results.EnumerateArray())
                {
                    items.Add(new
                    {
                        title   = r.GetProperty("title").GetString(),
                        url     = r.GetProperty("url").GetString(),
                        snippet = r.TryGetProperty("description", out var d) ? d.GetString() : ""
                    });
                }

                return JsonSerializer.Serialize(items, new JsonSerializerOptions { WriteIndented = true });
            }
            catch (Exception ex)
            {
                Console.WriteLine($"  ⚠️  Brave search failed ({ex.Message}), using stub results.");
            }
        }

        // Stub results so the agent loop works without a search API key
        var stubResults = new[]
        {
            new { title = $"{query} - Wikipedia",           url = $"https://en.wikipedia.org/wiki/{Uri.EscapeDataString(query)}", snippet = $"Comprehensive overview of {query} covering history, key concepts, and recent developments." },
            new { title = $"{query} – Latest Research",     url = $"https://arxiv.org/search/?query={Uri.EscapeDataString(query)}", snippet = $"Recent academic papers and research findings related to {query}." },
            new { title = $"Understanding {query} | Blog",  url = $"https://example.com/blog/{Uri.EscapeDataString(query)}",        snippet = $"An in-depth blog post explaining {query}, its applications, and future directions." },
        };

        return JsonSerializer.Serialize(stubResults, new JsonSerializerOptions { WriteIndented = true });
    }
}

/// <summary>Notepad tool that lets the agent save and retrieve research notes.</summary>
public class NotepadTool
{
    private readonly List<NoteEntry> _notes = [];

    [Description("Save a research note with its source URL. Call this for every important fact you find.")]
    public string AddNote(
        [Description("The note text to save")]        string note,
        [Description("The source URL for this note")] string sourceUrl)
    {
        _notes.Add(new NoteEntry(note, sourceUrl));
        Console.WriteLine($"  📝 Note #{_notes.Count} saved.");
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes to review before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var lines = _notes.Select((n, i) => $"[{i + 1}] {n.Note}  (source: {n.SourceUrl})");
        return string.Join('\n', lines);
    }

    public void Clear() => _notes.Clear();

    private sealed record NoteEntry(string Note, string SourceUrl);
}

